defmodule MyAppWeb.UserController do
  use MyAppWeb, :controller
  alias MyApp.Accounts
  alias MyApp.Accounts.User
  alias MyApp.Repo

  def update(conn, %{"id" => id} = params) do
    with {:ok, user} <- Accounts.get_user_by_id_and_tenant(id, get_tenant_id(conn)),
         {:ok, updated_user} <- update_user_with_authorization(conn, user, params) do
      conn
      |> put_status(:ok)
      |> render("show.json", user: updated_user)
    else
      {:error, :unauthorized} ->
        conn
        |> put_status(:forbidden)
        |> json(%{error: "Unauthorized"})
      {:error, changeset} ->
        conn
        |> put_status(:bad_request)
        |> render("error.json", changeset: changeset)
      {:error, reason} ->
        conn
        |> put_status(:internal_server_error)
        |> json(%{error: to_string(reason)})
    end
  end

  defp update_user_with_authorization(conn, user, params) do
    if can_update_user?(conn, user) do
      allowed_fields = get_allowed_update_fields(conn, user)
      filtered_params = filter_params(params, allowed_fields)
      
      user
      |> User.changeset(filtered_params)
      |> Repo.update()
    else
      {:error, :unauthorized}
    end
  end

  defp can_update_user?(conn, user) do
    current_user = get_current_user(conn)
    
    case {current_user.role, user.id} do
      {"admin", _} -> true
      {"user", user_id} when user_id == user.id -> true
      _ -> false
    end
  end

  defp get_allowed_update_fields(conn, user) do
    current_user = get_current_user(conn)
    
    case current_user.role do
      "admin" -> 
        [:first_name, :last_name, :email, :phone, :role, :credits, :verified_status, :account_type]
      "user" ->
        [:first_name, :last_name, :email, :phone]
      _ ->
        []
    end
  end

  defp filter_params(params, allowed_fields) do
    params
    |> Map.take(allowed_fields)
    |> Enum.into(%{})
  end

  defp get_current_user(conn) do
    conn.assigns.current_user
  end

  defp get_tenant_id(conn) do
    conn.assigns.tenant_id
  end
